import React, { useEffect, useState } from 'react';
import axios from 'axios';
import NoteForm from './components/NoteForm';
import NoteList from './components/NoteList';

function App() {
  const [notes, setNotes] = useState([]);

  const fetchNotes = async () => {
    try {
      const res = await axios.get('http://localhost:5001/api/notes');
      setNotes(res.data);
    } catch (err) { console.error(err); }
  };

  useEffect(() => { fetchNotes(); }, []);

  const dashboardStyle = {
    display: 'flex',
    minHeight: '100vh',
    backgroundColor: '#f8fafc',
    fontFamily: "'Inter', sans-serif",
    color: '#1e293b',
  };

  const sidebarStyle = {
    width: '400px',
    backgroundColor: '#ffffff',
    borderRight: '1px solid #e2e8f0',
    padding: '40px 30px',
    position: 'sticky',
    top: 0,
    height: '100vh',
    display: 'flex',
    flexDirection: 'column',
  };

  const mainContentStyle = {
    flex: 1,
    padding: '40px 60px',
    overflowY: 'auto',
  };

  return (
    <div style={dashboardStyle}>
      {/* Sidebar: Entry Area */}
      <aside style={sidebarStyle}>
        <div style={{ marginBottom: '40px' }}>
          <h1 style={{ fontSize: '24px', fontWeight: '800', color: '#6366f1', margin: 0 }}>DevVault</h1>
          <p style={{ fontSize: '14px', color: '#64748b', marginTop: '4px' }}>Cloud & DevOps Journal</p>
        </div>
        <NoteForm fetchNotes={fetchNotes} />
      </aside>

      {/* Main: Your Notes Area */}
      <main style={mainContentStyle}>
        <header style={{ marginBottom: '30px', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
          <h2 style={{ fontSize: '28px', fontWeight: '700' }}>Your Notes</h2>
          <span style={{ background: '#eef2ff', color: '#6366f1', padding: '6px 14px', borderRadius: '20px', fontSize: '13px', fontWeight: '600' }}>
            {notes.length} Total Snippets
          </span>
        </header>
        <NoteList notes={notes} fetchNotes={fetchNotes} />
      </main>
    </div>
  );
}

export default App;
